import React, { Fragment } from "react";
import { Typography } from "@material-ui/core";
import { Bar } from "react-chartjs-2";

// interface Props {
//   title: string;
//   labels: Array<string>;
//   data: Array<number>;
//   chartoptions: any;
// }

const BarChart = ({ title, labels, data, chartoptions }) => {
  const chartData = {
    labels: labels,
    datasets: [
      {
        label: chartoptions.label,
        backgroundColor: "rgba(255,99,132,0.2)",
        borderColor: "rgba(255,99,132,1)",
        borderWidth: 1,
        hoverBackgroundColor: "rgba(255,99,132,0.4)",
        hoverBorderColor: "rgba(255,99,132,1)",
        data: data,
      },
    ],
  };

  const options = {
    legend: {
      display: false,
    },
    scales: {
      xAxes: [
        {
          ticks: {
            fontSize: 13,
            stepSize: 10,
            autoSkip: false,
          },
          beginAtZero: true,
        },
      ],
    },
    indexAxis: "y",
    elements: {
      bar: {
        borderWidth: 1,
      },
    },
    responsive: true,
    plugins: {
      legend: {
        position: "bottom",
      },
      title: {
        display: false,
      },
    },
  };

  return (
    <Fragment>
      <Typography component="h6" variant="h6" color="secondary">
        {title}
      </Typography>
      <Bar
        data={chartData}
        width={chartoptions.width}
        height={chartoptions.height}
        options={options}
      />
    </Fragment>
  );
};

export default BarChart;
