import React, { Fragment } from 'react';
import { withStyles } from '@material-ui/core/styles';
import MuiAccordion from '@material-ui/core/Accordion';
import MuiAccordionSummary from '@material-ui/core/AccordionSummary';
import MuiAccordionDetails from '@material-ui/core/AccordionDetails';
import Typography from '@material-ui/core/Typography';
import ExpandMoreIcon from '@material-ui/icons/ExpandMore';

const Accordion = withStyles({
	root: {
		border: '1px solid rgba(0, 0, 0, .125)',
		boxShadow: 'none',
		'&:not(:last-child)': {
			borderBottom: 0,
		},
		'&:before': {
			display: 'none',
		},
		'&$expanded': {
			margin: 'auto',
		},
	},
	expanded: {},
})(MuiAccordion);

const AccordionSummary = withStyles({
	root: {
		backgroundColor: 'rgba(0, 0, 0, .03)',
		borderBottom: '1px solid rgba(0, 0, 0, .125)',
		marginBottom: -1,
		minHeight: 56,
		'&$expanded': {
			minHeight: 56,
		},
	},
	content: {
		'&$expanded': {
			margin: '12px 0',
		},
	},
	expanded: {},
})(MuiAccordionSummary);

const AccordionDetails = withStyles((theme) => ({
	root: {
		padding: theme.spacing(2),
	},
}))(MuiAccordionDetails);

interface Props {
	panel_name: string;
	aria_exp: string;
	id_header: string;
	panel_text: string;
	children: JSX.Element | JSX.Element[];
	expanded: boolean;
	handleChange: (panel: string) => ((event: React.ChangeEvent<{}>, newExpanded: boolean) => void) | undefined;
}

export default function Accordions({
	panel_name,
	aria_exp,
	id_header,
	panel_text,
	children,
	expanded,
	handleChange }: Props): JSX.Element {
	return (
		<Fragment>
			<Accordion square expanded={expanded} onChange={handleChange(panel_name)}>
				<AccordionSummary
					expandIcon={<ExpandMoreIcon />}
					aria-controls={aria_exp}
					id={id_header}>
					<Typography variant="subtitle2">{panel_text}</Typography>
				</AccordionSummary>
				<AccordionDetails
					style={{ flexDirection: "column" }}>
					{children}
				</AccordionDetails>
			</Accordion>
		</Fragment>
	);
}
